from __future__ import annotations
from enum import StrEnum
from pydantic import BaseModel
BI_SCHEMA_VERSION = '2026.03.20-analysis-r1'

class ReportFamily(StrEnum):
    SOV = 'share_of_voice'
    BUZZ = 'buzz'
    EMERGING_TOPICS = 'emerging_topics'
    TOP_ISSUES = 'top_issues'
    THREAD_CONTROVERSY = 'thread_controversy'
    CREATOR_SOURCE_BREAKDOWN = 'creator_source_breakdown'
    INSIGHT_CARDS = 'insight_cards'

class MeasurementKind(StrEnum):
    GOLD = 'gold_like_direct_aggregate'
    PROXY = 'proxy'
    HYBRID = 'hybrid'

class ReportContract(BaseModel):
    report_name: str
    report_family: ReportFamily
    report_version: str
    grain: str
    time_window_semantics: str
    ranking_semantics: str
    delta_semantics: str
    unresolved_handling: str
    measurement_kind: MeasurementKind
    intended_use: str
    anti_use: str

def bi_contract_registry():
    return {'sov_report': ReportContract(report_name='sov_report', report_family=ReportFamily.SOV, report_version='1.2.0', grain='canonical entity row', time_window_semantics='report summarizes the full analysis slice; delta fields compare the later chronological half of the slice against the earlier half when posted_at is available', ranking_semantics='rows ranked by effective mention-share descending when weighting_mode!=raw; raw mention share remains available alongside effective fields', delta_semantics='delta_kind=intra_window_delta in v1.1; delta_share and delta_count are later-half minus earlier-half mention-share and mention-count deltas within the same analysis slice', unresolved_handling='unresolved mentions are excluded from entity rows and reported separately in unresolved_summary; dedup/spam weighting does not remove rows and only affects effective fields when enabled', measurement_kind=MeasurementKind.GOLD, intended_use='business-facing entity attention and share comparisons', anti_use='not reach, audience size, or sentiment quality'), 'buzz_report': ReportContract(report_name='buzz_report', report_family=ReportFamily.BUZZ, report_version='1.2.0', grain='entity row and reporting topic row', time_window_semantics='report summarizes the full analysis slice; growth components compare later vs earlier chronological half-window when available', ranking_semantics='rows ranked by buzz_score_proxy descending; buzz_score_proxy uses effective mention volume when weighting_mode!=raw while preserving raw mention counts alongside effective fields', delta_semantics='delta_kind=intra_window_delta in v1.1; delta fields compare later-half counts against earlier-half counts within the same analysis slice', unresolved_handling='entity buzz excludes unresolved entities from ranked rows; topic buzz suppresses weak/noisy topics from primary ranking unless no stable topics exist', measurement_kind=MeasurementKind.HYBRID, intended_use='attention and momentum tracking for entities and topics', anti_use='not a direct measure of market share, sales, or unique reach'), 'emerging_topics_report': ReportContract(report_name='emerging_topics_report', report_family=ReportFamily.EMERGING_TOPICS, report_version='1.1.0', grain='reporting topic row', time_window_semantics='report summarizes the current analysis slice and compares topic artifacts to the latest available prior artifact snapshot', ranking_semantics='rows ranked by growth_delta descending, then quality_score descending', delta_semantics='growth_delta is current topic_size minus matched prior artifact topic_size; rows require quality and noise gating', unresolved_handling='topics without stable reviewed/effective identity fall back to raw topic identity and remain explicitly labeled', measurement_kind=MeasurementKind.HYBRID, intended_use='surfacing quality-gated emerging discussion themes', anti_use='not every first appearance is an emerging topic and weak/noisy clusters are not business signals'), 'top_issues_report': ReportContract(report_name='top_issues_report', report_family=ReportFamily.TOP_ISSUES, report_version='1.1.0', grain='issue class row', time_window_semantics='report summarizes the full analysis slice; growth components compare later vs earlier chronological half-window when available', ranking_semantics='rows ranked by issue_pressure_proxy descending; issue_pressure_proxy sums severity-weighted and evidence-weighted issue facts', delta_semantics='delta_kind=intra_window_delta in v1.1; growth_delta_mentions is later-half minus earlier-half distinct mention count for the issue class', unresolved_handling='target unresolved state does not suppress issue inclusion; null issue classes are excluded', measurement_kind=MeasurementKind.HYBRID, intended_use='ranking issue pressure with severity and evidence context', anti_use='not a verified incident rate or a causal root-cause diagnosis'), 'thread_controversy_report': ReportContract(report_name='thread_controversy_report', report_family=ReportFamily.THREAD_CONTROVERSY, report_version='1.0.0', grain='thread row', time_window_semantics='report summarizes the current analysis slice at root thread grain', ranking_semantics='rows ranked by controversy_score_proxy descending', delta_semantics='no cross-window delta; component values are same-slice structural and polarity-conflict proxies', unresolved_handling='entity or topic unresolved states do not affect controversy scoring', measurement_kind=MeasurementKind.PROXY, intended_use='surfacing threads that may merit analyst review for conflict-heavy conversational structure', anti_use='not a validated misinformation, harm, or public-safety metric'), 'creator_source_breakdown_report': ReportContract(report_name='creator_source_breakdown_report', report_family=ReportFamily.CREATOR_SOURCE_BREAKDOWN, report_version='1.0.0', grain='creator(author_id), thread initiator(author_id), and source platform rows', time_window_semantics='report summarizes the full analysis slice', ranking_semantics='rows ranked by volume descending within each grouping family', delta_semantics='no delta in v1; report focuses on current-slice contribution shares and associations', unresolved_handling='entity or topic unresolved states do not suppress creator or source inclusion; association fields skip null labels', measurement_kind=MeasurementKind.GOLD, intended_use='understanding who is contributing conversation volume and on which channels', anti_use='not influence, audience reach, or creator quality'), 'insight_card_bundle': ReportContract(report_name='insight_card_bundle', report_family=ReportFamily.INSIGHT_CARDS, report_version='2.0.0', grain='card row', time_window_semantics='cards inherit the analysis slice and report filters from their source BI reports', ranking_semantics='cards are generated from report-level priority conditions, not raw-mart top-k alone', delta_semantics='cards reuse the delta semantics of the source reports they summarize', unresolved_handling='cards preserve unresolved handling from the source reports and do not reinterpret it independently', measurement_kind=MeasurementKind.HYBRID, intended_use='business-facing narrative summaries with evidence and confidence', anti_use='not a substitute for inspecting underlying report rows or raw evidence')}
